window._topicalGuideData = [{"id":"berit","hebrew":"בְּרִית","hebrewRoot":"ברית","transliteration":"berit","english":"Covenant","category":"Covenant","definitionHeb":"הַסְכָּמָה מְחַיֶּבֶת בֵּין אֱלֹהִים לְעַמּוֹ. בְּסֵפֶר מוֹרְמוֹן, הַבְּרִית הָאַבְרָהָמִית הִיא נוֹשֵׂא מֶרְכָּזִי—הַבְטָחַת אֱלֹהִים לְבָרֵךְ אֶת כָּל מִשְׁפְּחוֹת הָאָרֶץ דֶּרֶךְ זַרְעוֹ שֶׁל אַבְרָהָם.","definitionEn":"A binding agreement between God and His people. In the Book of Mormon, the Abrahamic covenant is a central theme—God's promise to bless all families of the earth through Abraham's seed. Prophets repeatedly call upon the people to enter into covenant with God through repentance and baptism.","hebrewForms":["בְּרִית","בְּרִיתוֹ","בְּרִיתִי","הַבְּרִית","בִּבְרִית","בְּרִיתָם"],"verseRefs":[{"label":"1 Nephi 14:8","chapterId":"ch14","verse":8},{"label":"1 Nephi 15:14","chapterId":"ch15","verse":14},{"label":"1 Nephi 17:40","chapterId":"ch17","verse":40},{"label":"1 Nephi 22:9","chapterId":"ch22","verse":9},{"label":"2 Nephi 6:12","chapterId":"2n-ch6","verse":12},{"label":"2 Nephi 9:1","chapterId":"2n-ch9","verse":1},{"label":"2 Nephi 11:5","chapterId":"2n-ch11","verse":5},{"label":"3 Nephi 20:25","chapterId":"3n-ch20","verse":25},{"label":"3 Nephi 29:3","chapterId":"3n-ch29","verse":3},{"label":"Mormon 5:20","chapterId":"mm-ch5","verse":20},{"label":"Mormon 7:10","chapterId":"mm-ch7","verse":10},{"label":"Moroni 10:31","chapterId":"mr-ch10","verse":31}],"relatedEntries":["chesed","emunah","teshuvah"],"majorTheme":true},{"id":"chesed","hebrew":"חֶסֶד","hebrewRoot":"חסד","transliteration":"chesed","english":"Lovingkindness / Covenant Loyalty","category":"God","definitionHeb":"אַהֲבַת חֶסֶד שֶׁל אֱלֹהִים וְנֶאֱמָנוּתוֹ לִבְרִיתוֹ. חֶסֶד אֵינוֹ רַק רַחֲמִים, אֶלָּא נֶאֱמָנוּת מְחַיֶּבֶת הַנּוֹבַעַת מִיַּחַס הַבְּרִית. בְּסֵפֶר מוֹרְמוֹן, חַסְדֵּי ה' הֵם הַיְסוֹד לִגְאֻלַּת עַמּוֹ.","definitionEn":"God's steadfast love and loyalty to His covenant. Chesed is not merely compassion but an obligating faithfulness arising from the covenant relationship. In the Book of Mormon, God's lovingkindness is the foundation for redeeming His people despite their failings.","hebrewForms":["חֶסֶד","חַסְדּוֹ","חַסְדֶּךָ","חֲסָדָיו","חֲסָדֶיךָ","בְּחֶסֶד","הַחֶסֶד"],"verseRefs":[{"label":"1 Nephi 8:8","chapterId":"ch8","verse":8},{"label":"2 Nephi 4:26","chapterId":"2n-ch4","verse":26},{"label":"2 Nephi 9:8","chapterId":"2n-ch9","verse":8},{"label":"2 Nephi 9:53","chapterId":"2n-ch9","verse":53},{"label":"Mosiah 28:4","chapterId":"mo-ch28","verse":4},{"label":"Alma 9:26","chapterId":"al-ch9","verse":26},{"label":"Alma 26:35","chapterId":"al-ch26","verse":35},{"label":"Alma 42:15","chapterId":"al-ch42","verse":15},{"label":"Alma 42:23","chapterId":"al-ch42","verse":23},{"label":"3 Nephi 22:8","chapterId":"3n-ch22","verse":8},{"label":"Moroni 8:19","chapterId":"mr-ch8","verse":19}],"relatedEntries":["berit","rachamim","geulah","chen"],"majorTheme":true},{"id":"tamim","hebrew":"תָּמִים","hebrewRoot":"תמם","transliteration":"tamim","english":"Blameless / Perfect / Wholeness","category":"Righteousness","definitionHeb":"שְׁלֵמוּת, תֹּם, וְיֹשֶׁר לִפְנֵי אֱלֹהִים. בְּסֵפֶר מוֹרְמוֹן, הַמּוּשָׂג מְקַשֵּׁר בֵּין שְׁלֵמוּת מוּסָרִית לְבֵין הַשְּׁלֵמוּת שֶׁבָּאָה דֶּרֶךְ כַּפָּרַת הַמָּשִׁיחַ.","definitionEn":"Wholeness, integrity, and uprightness before God. In the Book of Mormon, this concept connects moral completeness to the perfection that comes through the Messiah's atonement. Believers are called to walk blamelessly before God while relying on Christ to make them whole.","hebrewForms":["תָּמִים","תָּם","תְּמִימִים","תֻּמָּה","בְּתֹם"],"verseRefs":[{"label":"2 Nephi 1:23","chapterId":"2n-ch1","verse":23},{"label":"2 Nephi 9:14","chapterId":"2n-ch9","verse":14},{"label":"Mosiah 2:22","chapterId":"mo-ch2","verse":22},{"label":"Mosiah 3:4","chapterId":"mo-ch3","verse":4},{"label":"Mosiah 4:6","chapterId":"mo-ch4","verse":6},{"label":"Alma 34:23","chapterId":"al-ch34","verse":23},{"label":"Alma 34:36","chapterId":"al-ch34","verse":36},{"label":"3 Nephi 12:48","chapterId":"3n-ch12","verse":48},{"label":"3 Nephi 27:27","chapterId":"3n-ch27","verse":27},{"label":"Moroni 10:32","chapterId":"mr-ch10","verse":32}],"relatedEntries":["tsedek","tahor","kaparah"],"majorTheme":true},{"id":"geulah","hebrew":"גְּאֻלָּה","hebrewRoot":"גאל","transliteration":"geulah","english":"Redemption","category":"Salvation","definitionHeb":"פְּדוּת וְהַצָּלָה מִשִּׁעְבּוּד. בַּמִּקְרָא, הַגּוֹאֵל הוּא קָרוֹב מִשְׁפָּחָה הַפּוֹדֶה אֶת קְרוֹבוֹ. בְּסֵפֶר מוֹרְמוֹן, הַמָּשִׁיחַ הוּא הַגּוֹאֵל הַגָּדוֹל הַפּוֹדֶה אֶת עַמּוֹ מֵחֵטְא וּמָוֶת.","definitionEn":"Deliverance and liberation from bondage. In the Bible, the goel is a kinsman who redeems a relative. In the Book of Mormon, the Messiah is the great Redeemer who delivers His people from sin and death through His atoning sacrifice.","hebrewForms":["גְּאֻלָּה","גּוֹאֵל","גָּאַל","נִגְאַל","גְּאוּלִים","הַגּוֹאֵל"],"verseRefs":[{"label":"2 Nephi 2:26","chapterId":"2n-ch2","verse":26},{"label":"2 Nephi 6:18","chapterId":"2n-ch6","verse":18},{"label":"Mosiah 3:11","chapterId":"mo-ch3","verse":11},{"label":"Mosiah 18:2","chapterId":"mo-ch18","verse":2},{"label":"Alma 5:15","chapterId":"al-ch5","verse":15},{"label":"Alma 9:27","chapterId":"al-ch9","verse":27},{"label":"Alma 12:25","chapterId":"al-ch12","verse":25},{"label":"Alma 22:13","chapterId":"al-ch22","verse":13},{"label":"Alma 34:16","chapterId":"al-ch34","verse":16},{"label":"Helaman 5:9","chapterId":"he-ch5","verse":9},{"label":"Helaman 14:17","chapterId":"he-ch14","verse":17},{"label":"Ether 3:14","chapterId":"et-ch3","verse":14}],"relatedEntries":["yeshuah","kaparah","pidyon","chesed"],"majorTheme":true},{"id":"shalom","hebrew":"שָׁלוֹם","hebrewRoot":"שלם","transliteration":"shalom","english":"Peace / Wholeness","category":"Blessing","definitionHeb":"שְׁלֵמוּת, שַׁלְוָה, וְהַרְמוֹנְיָה. שָׁלוֹם אֵינוֹ רַק הֶעְדֵּר מִלְחָמָה, אֶלָּא מַצָּב שֶׁל שְׁלֵמוּת רוּחָנִית. בְּסֵפֶר מוֹרְמוֹן, שָׁלוֹם אֲמִתִּי בָּא דֶּרֶךְ אֱמוּנָה בַּמָּשִׁיחַ וְצִיּוּת לְמִצְוֹתָיו.","definitionEn":"Wholeness, tranquility, and harmony. Shalom is not merely the absence of war but a state of spiritual completeness. In the Book of Mormon, true peace comes through faith in the Messiah and obedience to His commandments.","hebrewForms":["שָׁלוֹם","שְׁלוֹם","הַשָּׁלוֹם","בְּשָׁלוֹם","שַׁלְוָה"],"verseRefs":[{"label":"1 Nephi 14:7","chapterId":"ch14","verse":7},{"label":"1 Nephi 20:18","chapterId":"ch20","verse":18},{"label":"2 Nephi 4:27","chapterId":"2n-ch4","verse":27},{"label":"2 Nephi 26:9","chapterId":"2n-ch26","verse":9},{"label":"Mosiah 4:13","chapterId":"mo-ch4","verse":13},{"label":"Mosiah 27:4","chapterId":"mo-ch27","verse":4},{"label":"Mosiah 27:37","chapterId":"mo-ch27","verse":37},{"label":"Alma 7:27","chapterId":"al-ch7","verse":27},{"label":"Alma 22:25","chapterId":"al-ch22","verse":25},{"label":"Alma 36:19","chapterId":"al-ch36","verse":19},{"label":"4 Nephi 1:4","chapterId":"4n-ch1","verse":4},{"label":"Helaman 5:47","chapterId":"he-ch5","verse":47}],"relatedEntries":["berit","tamim","berakhah","simchah"],"majorTheme":true},{"id":"emunah","hebrew":"אֱמוּנָה","hebrewRoot":"אמן","transliteration":"emunah","english":"Faith","category":"Salvation","definitionHeb":"אֱמוּנָה וּבִטָּחוֹן בֵּאלֹהִים וּבִדְבָרָיו. אֱמוּנָה אֲמִתִּית מוֹבִילָה לְמַעֲשֶׂה וּלְהִתְחַזְּקוּת רוּחָנִית.","definitionEn":"Belief and trust in God and His word. True faith leads to action and spiritual strengthening, and is the foundation for all righteousness.","hebrewForms":["אֱמוּנָה","הֶאֱמִין","הֶאֱמִינוּ","יַאֲמִין","נֶאֱמָן","בֶּאֱמוּנָה"],"verseRefs":[{"label":"Enos 1:8","chapterId":"en-ch1","verse":8},{"label":"Alma 32:21","chapterId":"al-ch32","verse":21},{"label":"Alma 34:17","chapterId":"al-ch34","verse":17},{"label":"Ether 3:15","chapterId":"et-ch3","verse":15},{"label":"Ether 12:6","chapterId":"et-ch12","verse":6},{"label":"Moroni 7:42","chapterId":"mr-ch7","verse":42},{"label":"Moroni 10:4","chapterId":"mr-ch10","verse":4}],"relatedEntries":["bitachon","tikvah","teshuvah"],"majorTheme":false},{"id":"teshuvah","hebrew":"תְּשׁוּבָה","hebrewRoot":"שוב","transliteration":"teshuvah","english":"Repentance","category":"Salvation","definitionHeb":"חֲזָרָה אֶל אֱלֹהִים דֶּרֶךְ הַכָּרָה בַּחֵטְא, חֲרָטָה, וְשִׁנּוּי דֶּרֶךְ. תְּשׁוּבָה הִיא תְּנַאי לִגְאֻלָּה.","definitionEn":"Returning to God through acknowledgment of sin, remorse, and change of course. Repentance is a prerequisite for redemption and spiritual renewal.","hebrewForms":["תְּשׁוּבָה","שָׁב","שׁוּבוּ","וַיָּשָׁב","לָשׁוּב"],"verseRefs":[{"label":"2 Nephi 9:23","chapterId":"2n-ch9","verse":23},{"label":"Mosiah 4:10","chapterId":"mo-ch4","verse":10},{"label":"Mosiah 26:29","chapterId":"mo-ch26","verse":29},{"label":"Alma 34:33","chapterId":"al-ch34","verse":33},{"label":"Alma 42:22","chapterId":"al-ch42","verse":22},{"label":"3 Nephi 9:22","chapterId":"3n-ch9","verse":22},{"label":"Moroni 8:24","chapterId":"mr-ch8","verse":24}],"relatedEntries":["chet","selichah","emunah"],"majorTheme":false},{"id":"kaparah","hebrew":"כַּפָּרָה","hebrewRoot":"כפר","transliteration":"kaparah","english":"Atonement","category":"Salvation","definitionHeb":"כִּסּוּי הַחֵטְא וְרִצּוּי לִפְנֵי אֱלֹהִים. כַּפָּרַת הַמָּשִׁיחַ הִיא הַיְסוֹד לִסְלִיחָה וְגְאֻלָּה.","definitionEn":"Covering of sin and reconciliation before God. The Messiah's atonement is the foundation for forgiveness and redemption of all mankind.","hebrewForms":["כַּפָּרָה","כִּפֵּר","כִּפּוּר","הַכַּפָּרָה","כָּפַר"],"verseRefs":[{"label":"2 Nephi 2:7","chapterId":"2n-ch2","verse":7},{"label":"Jacob 4:11","chapterId":"jc-ch4","verse":11},{"label":"Mosiah 4:6","chapterId":"mo-ch4","verse":6},{"label":"Mosiah 13:28","chapterId":"mo-ch13","verse":28},{"label":"Alma 34:8","chapterId":"al-ch34","verse":8},{"label":"Alma 42:23","chapterId":"al-ch42","verse":23},{"label":"3 Nephi 9:21","chapterId":"3n-ch9","verse":21},{"label":"3 Nephi 27:15","chapterId":"3n-ch27","verse":15}],"relatedEntries":["geulah","yeshuah","chet"],"majorTheme":false},{"id":"yeshuah","hebrew":"יְשׁוּעָה","hebrewRoot":"ישע","transliteration":"yeshuah","english":"Salvation","category":"Salvation","definitionHeb":"הַצָּלָה וְשִׁחְרוּר אֱלֹהִי מֵחֵטְא, מָוֶת, וְסֵבֶל. יְשׁוּעָה בָּאָה דֶּרֶךְ הַמָּשִׁיחַ בִּלְבַד.","definitionEn":"Divine deliverance from sin, death, and suffering. Salvation comes only through the Messiah and His infinite sacrifice.","hebrewForms":["יְשׁוּעָה","יֵשַׁע","מוֹשִׁיעַ","הוֹשִׁיעַ","הַיְשׁוּעָה"],"verseRefs":[{"label":"2 Nephi 2:4","chapterId":"2n-ch2","verse":4},{"label":"2 Nephi 9:8","chapterId":"2n-ch9","verse":8},{"label":"Mosiah 3:9","chapterId":"mo-ch3","verse":9},{"label":"Alma 12:25","chapterId":"al-ch12","verse":25},{"label":"Alma 42:13","chapterId":"al-ch42","verse":13},{"label":"3 Nephi 27:16","chapterId":"3n-ch27","verse":16}],"relatedEntries":["geulah","kaparah","mashiach"],"majorTheme":false},{"id":"ruach_haqodesh","hebrew":"רוּחַ הַקֹּדֶשׁ","hebrewRoot":"רוח","transliteration":"ruach haqodesh","english":"Holy Spirit","category":"God","definitionHeb":"רוּחַ אֱלֹהִים הַקְּדוֹשָׁה, הַמְּגַלָּה אֱמֶת וּמַנְחָה אֶת הַמַּאֲמִינִים בְּדֶרֶךְ הַצֶּדֶק.","definitionEn":"The Holy Spirit of God, who reveals truth and guides believers in the path of righteousness.","hebrewForms":["רוּחַ הַקֹּדֶשׁ","הָרוּחַ","רוּחַ אֱלֹהִים","רוּחוֹ"],"verseRefs":[{"label":"1 Nephi 11:11","chapterId":"ch11","verse":11},{"label":"2 Nephi 31:13","chapterId":"2n-ch31","verse":13},{"label":"2 Nephi 32:5","chapterId":"2n-ch32","verse":5},{"label":"Alma 5:46","chapterId":"al-ch5","verse":46},{"label":"3 Nephi 19:9","chapterId":"3n-ch19","verse":9},{"label":"Moroni 10:5","chapterId":"mr-ch10","verse":5}],"relatedEntries":["elohim","qodesh","nevuah"],"majorTheme":false},{"id":"mashiach","hebrew":"מָשִׁיחַ","hebrewRoot":"משח","transliteration":"mashiach","english":"Messiah","category":"God","definitionHeb":"הַמָּשׁוּחַ, הַנִּבְחָר עַל יְדֵי אֱלֹהִים לִגְאֹל אֶת עַמּוֹ. נְבִיאֵי סֵפֶר מוֹרְמוֹן הֵעִידוּ עַל בּוֹאוֹ.","definitionEn":"The Anointed One, chosen by God to redeem His people. Book of Mormon prophets testified of His coming centuries before His birth.","hebrewForms":["מָשִׁיחַ","הַמָּשִׁיחַ","מְשִׁיחוֹ","נִמְשַׁח"],"verseRefs":[{"label":"1 Nephi 1:19","chapterId":"ch1","verse":19},{"label":"2 Nephi 2:8","chapterId":"2n-ch2","verse":8},{"label":"2 Nephi 10:3","chapterId":"2n-ch10","verse":3},{"label":"2 Nephi 25:19","chapterId":"2n-ch25","verse":19},{"label":"Jacob 4:4","chapterId":"jc-ch4","verse":4},{"label":"Alma 16:19","chapterId":"al-ch16","verse":19},{"label":"Helaman 8:22","chapterId":"he-ch8","verse":22}],"relatedEntries":["yeshuah","geulah","kaparah"],"majorTheme":false},{"id":"tsedek","hebrew":"צֶדֶק","hebrewRoot":"צדק","transliteration":"tsedek","english":"Righteousness","category":"Righteousness","definitionHeb":"יֹשֶׁר, צְדָקָה, וּמַעֲשִׂים נְכוֹנִים בְּעֵינֵי אֱלֹהִים. הַצַּדִּיק הוֹלֵךְ בְּדֶרֶךְ ה'.","definitionEn":"Uprightness, justice, and right action in the eyes of God. The righteous walk in the way of the Lord.","hebrewForms":["צֶדֶק","צְדָקָה","צַדִּיק","צַדִּיקִים","בְּצֶדֶק"],"verseRefs":[{"label":"2 Nephi 1:23","chapterId":"2n-ch1","verse":23},{"label":"2 Nephi 9:14","chapterId":"2n-ch9","verse":14},{"label":"Alma 34:23","chapterId":"al-ch34","verse":23},{"label":"Alma 34:36","chapterId":"al-ch34","verse":36},{"label":"3 Nephi 22:14","chapterId":"3n-ch22","verse":14},{"label":"Ether 8:26","chapterId":"et-ch8","verse":26}],"relatedEntries":["tamim","mishpat","tahor"],"majorTheme":false},{"id":"mishpat","hebrew":"מִשְׁפָּט","hebrewRoot":"שפט","transliteration":"mishpat","english":"Justice / Judgment","category":"God","definitionHeb":"דִּין וּמִשְׁפָּט אֱלֹהִי. אֱלֹהִים שׁוֹפֵט בְּצֶדֶק אֶת כָּל מַעֲשֵׂי בְּנֵי הָאָדָם.","definitionEn":"Divine justice and judgment. God judges all the deeds of mankind with perfect equity and righteousness.","hebrewForms":["מִשְׁפָּט","שׁוֹפֵט","שָׁפַט","הַמִּשְׁפָּט","שְׁפֹט"],"verseRefs":[{"label":"2 Nephi 9:14","chapterId":"2n-ch9","verse":14},{"label":"Mosiah 3:26","chapterId":"mo-ch3","verse":26},{"label":"Alma 12:15","chapterId":"al-ch12","verse":15},{"label":"Alma 34:16","chapterId":"al-ch34","verse":16},{"label":"Alma 41:14","chapterId":"al-ch41","verse":14},{"label":"Alma 42:25","chapterId":"al-ch42","verse":25}],"relatedEntries":["tsedek","rachamim","chesed"],"majorTheme":false},{"id":"rachamim","hebrew":"רַחֲמִים","hebrewRoot":"רחם","transliteration":"rachamim","english":"Mercy","category":"God","definitionHeb":"רַחֲמָנוּת אֱלֹהִית וְחֶמְלָה עַל הַחוֹטְאִים. רַחֲמֵי ה' מְאַזְּנִים אֶת מִדַּת הַדִּין.","definitionEn":"Divine compassion and pity for sinners. God's mercy balances His justice, making repentance and forgiveness possible.","hebrewForms":["רַחֲמִים","רַחוּם","רִחֵם","בְּרַחֲמָיו"],"verseRefs":[{"label":"Alma 15:10","chapterId":"al-ch15","verse":10},{"label":"Alma 34:16","chapterId":"al-ch34","verse":16},{"label":"Alma 42:15","chapterId":"al-ch42","verse":15},{"label":"Alma 42:24","chapterId":"al-ch42","verse":24},{"label":"Alma 42:30","chapterId":"al-ch42","verse":30},{"label":"3 Nephi 12:7","chapterId":"3n-ch12","verse":7}],"relatedEntries":["chesed","chen","mishpat"],"majorTheme":false},{"id":"chen","hebrew":"חֵן","hebrewRoot":"חנן","transliteration":"chen","english":"Grace","category":"Salvation","definitionHeb":"חֶסֶד חִנָּם מֵאֵת אֱלֹהִים, מַתָּנָה שֶׁאֵינָהּ תְּלוּיָה בְּזָכוּת. חֵן מַשְׁלִים אֶת מַאֲמַצֵּי הָאָדָם.","definitionEn":"The free gift of God's favor, unmerited and unearned. Grace complements human effort and enables believers to overcome weakness.","hebrewForms":["חֵן","חֲנוּנָה","חַנּוּן","בְּחֵן"],"verseRefs":[{"label":"2 Nephi 2:4","chapterId":"2n-ch2","verse":4},{"label":"2 Nephi 10:24","chapterId":"2n-ch10","verse":24},{"label":"Jacob 4:7","chapterId":"jc-ch4","verse":7},{"label":"Mosiah 18:16","chapterId":"mo-ch18","verse":16},{"label":"Ether 12:27","chapterId":"et-ch12","verse":27},{"label":"Moroni 7:2","chapterId":"mr-ch7","verse":2}],"relatedEntries":["chesed","yeshuah","kaparah"],"majorTheme":false},{"id":"ahavah","hebrew":"אַהֲבָה","hebrewRoot":"אהב","transliteration":"ahavah","english":"Love / Charity","category":"Righteousness","definitionHeb":"אַהֲבָה טְהוֹרָה, אַהֲבַת אֱלֹהִים וְהָאָדָם. אַהֲבָה הִיא הַמִּדָּה הַגְּדוֹלָה בְּיוֹתֵר.","definitionEn":"Pure love, the love of God and of fellow man. Charity is the greatest of all virtues and never fails.","hebrewForms":["אַהֲבָה","אָהַב","אֹהֵב","אַהֲבַת","בְּאַהֲבָה"],"verseRefs":[{"label":"2 Nephi 26:30","chapterId":"2n-ch26","verse":30},{"label":"Mosiah 4:15","chapterId":"mo-ch4","verse":15},{"label":"Alma 7:24","chapterId":"al-ch7","verse":24},{"label":"Moroni 7:47","chapterId":"mr-ch7","verse":47},{"label":"Moroni 8:17","chapterId":"mr-ch8","verse":17}],"relatedEntries":["chesed","rachamim","shalom"],"majorTheme":false},{"id":"tefilah","hebrew":"תְּפִלָּה","hebrewRoot":"פלל","transliteration":"tefilah","english":"Prayer","category":"Worship","definitionHeb":"פְּנִיָּה לֵאלֹהִים בִּתְפִלָּה, בַּקָּשָׁה, וְהוֹדָיָה. תְּפִלָּה הִיא אֶמְצָעִי הַתִּקְשׁוֹרֶת עִם הַשָּׁמַיִם.","definitionEn":"Turning to God in supplication, petition, and thanksgiving. Prayer is the means of communication with heaven.","hebrewForms":["תְּפִלָּה","הִתְפַּלֵּל","תְּפִלּוֹת","מִתְפַּלֵּל"],"verseRefs":[{"label":"Enos 1:4","chapterId":"en-ch1","verse":4},{"label":"Alma 31:38","chapterId":"al-ch31","verse":38},{"label":"Alma 34:17","chapterId":"al-ch34","verse":17},{"label":"3 Nephi 18:20","chapterId":"3n-ch18","verse":20},{"label":"3 Nephi 19:35","chapterId":"3n-ch19","verse":35},{"label":"Moroni 7:48","chapterId":"mr-ch7","verse":48}],"relatedEntries":["emunah","teshuvah","avodah"],"majorTheme":false},{"id":"nevuah","hebrew":"נְבוּאָה","hebrewRoot":"נבא","transliteration":"nevuah","english":"Prophecy","category":"Revelation","definitionHeb":"דְּבַר ה' הַנִּמְסָר עַל יְדֵי נְבִיאִים. נְבוּאָה מְגַלָּה אֶת רְצוֹן אֱלֹהִים וְאֶת תָּכְנִיתוֹ.","definitionEn":"The word of the Lord delivered through prophets. Prophecy reveals God's will and His plan for His children.","hebrewForms":["נְבוּאָה","נָבִיא","נְבִיאִים","הִתְנַבֵּא","נִבָּא"],"verseRefs":[{"label":"1 Nephi 1:4","chapterId":"ch1","verse":4},{"label":"1 Nephi 22:12","chapterId":"ch22","verse":12},{"label":"2 Nephi 25:19","chapterId":"2n-ch25","verse":19},{"label":"Jacob 4:4","chapterId":"jc-ch4","verse":4},{"label":"Words of Mormon 1:4","chapterId":"wm-ch1","verse":4},{"label":"Alma 24:14","chapterId":"al-ch24","verse":14}],"relatedEntries":["davar","gilluy","sefer"],"majorTheme":false},{"id":"mitzvah","hebrew":"מִצְוָה","hebrewRoot":"צוה","transliteration":"mitzvah","english":"Commandment","category":"Covenant","definitionHeb":"צִוּוּי אֱלֹהִי, הוֹרָאָה מֵאֵת ה'. שְׁמִירַת הַמִּצְוֹת מְבִיאָה בְּרָכָה.","definitionEn":"A divine commandment, an instruction from God. Keeping the commandments brings blessings and spiritual protection.","hebrewForms":["מִצְוָה","מִצְוֹת","מִצְוֹתָיו","צִוָּה","צַו"],"verseRefs":[{"label":"1 Nephi 3:7","chapterId":"ch3","verse":7},{"label":"2 Nephi 31:10","chapterId":"2n-ch31","verse":10},{"label":"Mosiah 2:22","chapterId":"mo-ch2","verse":22},{"label":"Alma 7:24","chapterId":"al-ch7","verse":24},{"label":"3 Nephi 18:16","chapterId":"3n-ch18","verse":16}],"relatedEntries":["torah","berit","tsedek"],"majorTheme":false},{"id":"torah","hebrew":"תּוֹרָה","hebrewRoot":"ירה","transliteration":"torah","english":"Law / Instruction","category":"Covenant","definitionHeb":"הוֹרָאָה אֱלֹהִית, תּוֹרַת מֹשֶׁה וְתוֹרַת ה'. הַתּוֹרָה מַנְחָה אֶת עַם הַבְּרִית.","definitionEn":"Divine instruction, the Law of Moses and the teaching of God. The Torah guides the covenant people in the way of righteousness.","hebrewForms":["תּוֹרָה","תּוֹרַת","הַתּוֹרָה","הוֹרָה","מוֹרֶה"],"verseRefs":[{"label":"2 Nephi 5:10","chapterId":"2n-ch5","verse":10},{"label":"2 Nephi 25:24","chapterId":"2n-ch25","verse":24},{"label":"Jacob 4:5","chapterId":"jc-ch4","verse":5},{"label":"Mosiah 13:28","chapterId":"mo-ch13","verse":28},{"label":"Alma 25:15","chapterId":"al-ch25","verse":15}],"relatedEntries":["mitzvah","berit","davar"],"majorTheme":false},{"id":"qodesh","hebrew":"קֹדֶשׁ","hebrewRoot":"קדש","transliteration":"qodesh","english":"Holiness","category":"God","definitionHeb":"קְדֻשָּׁה, הַפְרָדָה מֵהַחֹל וְהִתְקָרְבוּת לֵאלֹהִים. הַקָּדוֹשׁ הוּא מוּבְדָּל לַעֲבוֹדַת ה'.","definitionEn":"Holiness, separation from the profane and drawing near to God. That which is holy is set apart for the service of the Lord.","hebrewForms":["קֹדֶשׁ","קָדוֹשׁ","קְדוֹשִׁים","הַקָּדוֹשׁ","קְדֻשָּׁה"],"verseRefs":[{"label":"2 Nephi 9:14","chapterId":"2n-ch9","verse":14},{"label":"Alma 5:24","chapterId":"al-ch5","verse":24},{"label":"Alma 13:12","chapterId":"al-ch13","verse":12},{"label":"3 Nephi 27:20","chapterId":"3n-ch27","verse":20},{"label":"Moroni 10:33","chapterId":"mr-ch10","verse":33}],"relatedEntries":["tahor","tamim","elohim"],"majorTheme":false},{"id":"kehunah","hebrew":"כְּהֻנָּה","hebrewRoot":"כהן","transliteration":"kehunah","english":"Priesthood","category":"Covenant","definitionHeb":"סַמְכוּת אֱלֹהִית לְפָעֹל בְּשֵׁם ה'. הַכְּהֻנָּה מְקַשֶּׁרֶת בֵּין שָׁמַיִם לָאָרֶץ.","definitionEn":"Divine authority to act in the name of the Lord. The priesthood connects heaven and earth through sacred ordinances.","hebrewForms":["כְּהֻנָּה","כֹּהֵן","כֹּהֲנִים","כִּהֵן","הַכֹּהֵן"],"verseRefs":[{"label":"2 Nephi 6:2","chapterId":"2n-ch6","verse":2},{"label":"Mosiah 18:17","chapterId":"mo-ch18","verse":17},{"label":"Alma 13:1","chapterId":"al-ch13","verse":1},{"label":"Alma 13:8","chapterId":"al-ch13","verse":8},{"label":"Alma 13:12","chapterId":"al-ch13","verse":12}],"relatedEntries":["qodesh","berit","zevach"],"majorTheme":false},{"id":"kavod","hebrew":"כָּבוֹד","hebrewRoot":"כבד","transliteration":"kavod","english":"Glory","category":"God","definitionHeb":"כְּבוֹד ה', הוֹדוֹ וּגְדֻלָּתוֹ. כְּבוֹד אֱלֹהִים מִתְגַּלֶּה לְעֵינֵי הַנְּבִיאִים.","definitionEn":"The glory of God, His splendor and majesty. God's glory is revealed to the eyes of prophets and the faithful.","hebrewForms":["כָּבוֹד","כְּבוֹד","הַכָּבוֹד","נִכְבָּד","כִּבֵּד"],"verseRefs":[{"label":"1 Nephi 11:6","chapterId":"ch11","verse":6},{"label":"2 Nephi 16:3","chapterId":"2n-ch16","verse":3},{"label":"Mosiah 4:11","chapterId":"mo-ch4","verse":11},{"label":"Alma 12:15","chapterId":"al-ch12","verse":15},{"label":"3 Nephi 11:3","chapterId":"3n-ch11","verse":3}],"relatedEntries":["elohim","qodesh","or"],"majorTheme":false},{"id":"bechirah","hebrew":"בְּחִירָה","hebrewRoot":"בחר","transliteration":"bechirah","english":"Agency / Choice","category":"Salvation","definitionHeb":"חֹפֶשׁ הַבְּחִירָה שֶׁנָּתַן אֱלֹהִים לָאָדָם. כָּל אָדָם בּוֹחֵר בֵּין טוֹב לְרָע.","definitionEn":"The freedom of choice given by God to mankind. Every person chooses between good and evil, and is accountable for their choices.","hebrewForms":["בְּחִירָה","בָּחַר","בֹּחֵר","הִבָּחֵר","בְּחִירָתוֹ"],"verseRefs":[{"label":"2 Nephi 2:16","chapterId":"2n-ch2","verse":16},{"label":"2 Nephi 2:27","chapterId":"2n-ch2","verse":27},{"label":"2 Nephi 10:23","chapterId":"2n-ch10","verse":23},{"label":"Mosiah 2:21","chapterId":"mo-ch2","verse":21},{"label":"Alma 12:31","chapterId":"al-ch12","verse":31},{"label":"Helaman 14:30","chapterId":"he-ch14","verse":30}],"relatedEntries":["nefilah","teshuvah","mitzvah"],"majorTheme":false},{"id":"anavah","hebrew":"עֲנָוָה","hebrewRoot":"ענה","transliteration":"anavah","english":"Humility","category":"Righteousness","definitionHeb":"עֲנָוָה וְשִׁפְלוּת רוּחַ לִפְנֵי אֱלֹהִים. הָעָנָו פָּתוּחַ לְקַבֵּל אֶת דְּבַר ה'.","definitionEn":"Meekness and lowliness of spirit before God. The humble are open to receiving the word of the Lord.","hebrewForms":["עֲנָוָה","עָנָו","עֲנָוִים","הִתְעַנָּה"],"verseRefs":[{"label":"2 Nephi 9:42","chapterId":"2n-ch9","verse":42},{"label":"Mosiah 4:11","chapterId":"mo-ch4","verse":11},{"label":"Alma 5:27","chapterId":"al-ch5","verse":27},{"label":"Alma 32:14","chapterId":"al-ch32","verse":14},{"label":"Ether 12:27","chapterId":"et-ch12","verse":27}],"relatedEntries":["teshuvah","tefilah","tamim"],"majorTheme":false},{"id":"gaavah","hebrew":"גַּאֲוָה","hebrewRoot":"גאה","transliteration":"gaavah","english":"Pride","category":"Sin","definitionHeb":"גָּאוֹן וְיוֹהֲרָה, הִתְנַשְּׂאוּת לִפְנֵי אֱלֹהִים וְאָדָם. הַגַּאֲוָה מַרְחִיקָה מֵאֱלֹהִים.","definitionEn":"Arrogance and haughtiness, exalting oneself above God and fellow man. Pride distances one from God and leads to destruction.","hebrewForms":["גַּאֲוָה","גֵּאָה","גֵּאִים","הִתְגָּאוּת"],"verseRefs":[{"label":"2 Nephi 9:42","chapterId":"2n-ch9","verse":42},{"label":"Jacob 2:16","chapterId":"jc-ch2","verse":16},{"label":"Alma 4:8","chapterId":"al-ch4","verse":8},{"label":"Alma 5:28","chapterId":"al-ch5","verse":28},{"label":"Helaman 3:36","chapterId":"he-ch3","verse":36},{"label":"Moroni 8:27","chapterId":"mr-ch8","verse":27}],"relatedEntries":["anavah","chet","rishah"],"majorTheme":false},{"id":"tsiyon","hebrew":"צִיּוֹן","hebrewRoot":"ציון","transliteration":"tsiyon","english":"Zion","category":"Covenant","definitionHeb":"מְקוֹם קָדוֹשׁ וְקְהִלַּת הַצַּדִּיקִים. צִיּוֹן הִיא הַחֶבְרָה הָאִידֵּאָלִית שֶׁל עַם ה'.","definitionEn":"A holy place and community of the righteous. Zion is the ideal society of God's people, united in one heart and one mind.","hebrewForms":["צִיּוֹן","הַצִּיּוֹן","בְּצִיּוֹן"],"verseRefs":[{"label":"1 Nephi 13:37","chapterId":"ch13","verse":37},{"label":"2 Nephi 8:3","chapterId":"2n-ch8","verse":3},{"label":"2 Nephi 12:3","chapterId":"2n-ch12","verse":3},{"label":"2 Nephi 26:30","chapterId":"2n-ch26","verse":30},{"label":"3 Nephi 16:18","chapterId":"3n-ch16","verse":18},{"label":"4 Nephi 1:4","chapterId":"4n-ch1","verse":4}],"relatedEntries":["berit","shalom","malkhut"],"majorTheme":false},{"id":"malkhut","hebrew":"מַלְכוּת","hebrewRoot":"מלך","transliteration":"malkhut","english":"Kingdom","category":"God","definitionHeb":"מַלְכוּת ה', שִׁלְטוֹן אֱלֹהִים עַל כָּל הָאָרֶץ. הַמֶּלֶךְ הָאֲמִתִּי הוּא אֱלֹהִים.","definitionEn":"The Kingdom of God, the divine rule over all the earth. The true King is God, and His kingdom shall prevail.","hebrewForms":["מַלְכוּת","מֶלֶךְ","מְלָכִים","מָלַךְ","הַמֶּלֶךְ"],"verseRefs":[{"label":"2 Nephi 10:14","chapterId":"2n-ch10","verse":14},{"label":"Mosiah 2:19","chapterId":"mo-ch2","verse":19},{"label":"Mosiah 29:13","chapterId":"mo-ch29","verse":13},{"label":"Alma 5:50","chapterId":"al-ch5","verse":50},{"label":"3 Nephi 12:10","chapterId":"3n-ch12","verse":10}],"relatedEntries":["elohim","tsiyon","mashiach"],"majorTheme":false},{"id":"derekh","hebrew":"דֶּרֶךְ","hebrewRoot":"דרך","transliteration":"derekh","english":"Way / Path","category":"Salvation","definitionHeb":"דֶּרֶךְ ה', הַמָּסְלוּל הָרוּחָנִי שֶׁעַל הַמַּאֲמִין לָלֶכֶת בּוֹ. יֵשׁ דֶּרֶךְ אַחַת לַיְשׁוּעָה.","definitionEn":"The way of the Lord, the spiritual path that the believer must walk. There is one way to salvation, and it is through the Messiah.","hebrewForms":["דֶּרֶךְ","דַּרְכּוֹ","דְּרָכָיו","בְּדֶרֶךְ","הַדֶּרֶךְ"],"verseRefs":[{"label":"1 Nephi 8:20","chapterId":"ch8","verse":20},{"label":"2 Nephi 4:32","chapterId":"2n-ch4","verse":32},{"label":"2 Nephi 9:41","chapterId":"2n-ch9","verse":41},{"label":"2 Nephi 31:9","chapterId":"2n-ch31","verse":9},{"label":"2 Nephi 31:21","chapterId":"2n-ch31","verse":21}],"relatedEntries":["torah","mitzvah","emunah"],"majorTheme":false},{"id":"chet","hebrew":"חֵטְא","hebrewRoot":"חטא","transliteration":"chet","english":"Sin","category":"Sin","definitionHeb":"הַחְטָאַת הַמַּטָּרָה, סְטִיָּה מִדֶּרֶךְ ה'. הַחֵטְא מַרְחִיק אֶת הָאָדָם מֵאֱלֹהִים.","definitionEn":"Missing the mark, deviation from God's way. Sin separates mankind from God and brings spiritual death.","hebrewForms":["חֵטְא","חָטָא","חֹטֵא","חֲטָאִים","חַטָּאת"],"verseRefs":[{"label":"Mosiah 2:38","chapterId":"mo-ch2","verse":38},{"label":"Mosiah 3:26","chapterId":"mo-ch3","verse":26},{"label":"Mosiah 4:10","chapterId":"mo-ch4","verse":10},{"label":"Alma 36:12","chapterId":"al-ch36","verse":12},{"label":"Alma 42:22","chapterId":"al-ch42","verse":22},{"label":"3 Nephi 9:2","chapterId":"3n-ch9","verse":2}],"relatedEntries":["avon","teshuvah","selichah"],"majorTheme":false},{"id":"avon","hebrew":"עָוֹן","hebrewRoot":"עון","transliteration":"avon","english":"Iniquity / Guilt","category":"Sin","definitionHeb":"עָוֹן, אַשְׁמָה, וְסְטִיָּה מוּסָרִית. הָעָוֹן מְכַבֵּד אֶת נֵטֶל הַנֶּפֶשׁ.","definitionEn":"Iniquity, guilt, and moral distortion. Iniquity burdens the soul and requires divine atonement for its removal.","hebrewForms":["עָוֹן","עֲוֹנוֹת","עֲוֹנוֹתֵיכֶם"],"verseRefs":[{"label":"Mosiah 14:5","chapterId":"mo-ch14","verse":5},{"label":"Alma 5:18","chapterId":"al-ch5","verse":18},{"label":"Alma 36:12","chapterId":"al-ch36","verse":12},{"label":"Alma 42:13","chapterId":"al-ch42","verse":13}],"relatedEntries":["chet","teshuvah","kaparah"],"majorTheme":false},{"id":"selichah","hebrew":"סְלִיחָה","hebrewRoot":"סלח","transliteration":"selichah","english":"Forgiveness","category":"Salvation","definitionHeb":"מְחִילָה וְסְלִיחָה עַל חֲטָאִים. אֱלֹהִים סוֹלֵחַ לַחוֹזְרִים בִּתְשׁוּבָה.","definitionEn":"Pardon and forgiveness for sins. God forgives those who sincerely repent and turn back to Him.","hebrewForms":["סְלִיחָה","סָלַח","נִסְלַח","מְחִילָה"],"verseRefs":[{"label":"Enos 1:5","chapterId":"en-ch1","verse":5},{"label":"Mosiah 4:3","chapterId":"mo-ch4","verse":3},{"label":"Mosiah 26:29","chapterId":"mo-ch26","verse":29},{"label":"Alma 36:19","chapterId":"al-ch36","verse":19},{"label":"Moroni 6:8","chapterId":"mr-ch6","verse":8}],"relatedEntries":["teshuvah","chesed","rachamim"],"majorTheme":false},{"id":"nefesh","hebrew":"נֶפֶשׁ","hebrewRoot":"נפש","transliteration":"nefesh","english":"Soul","category":"Humanity","definitionHeb":"הַנֶּפֶשׁ, מָהוּת הָאָדָם הַפְּנִימִית. הַנֶּפֶשׁ הִיא נִצְחִית וִיקָרָה בְּעֵינֵי אֱלֹהִים.","definitionEn":"The soul, the inner essence of a person. The soul is eternal and of great worth in the eyes of God.","hebrewForms":["נֶפֶשׁ","נַפְשׁוֹ","נַפְשֵׁנוּ","נְפָשׁוֹת"],"verseRefs":[{"label":"2 Nephi 9:39","chapterId":"2n-ch9","verse":39},{"label":"Jacob 2:21","chapterId":"jc-ch2","verse":21},{"label":"Alma 34:28","chapterId":"al-ch34","verse":28},{"label":"Alma 40:11","chapterId":"al-ch40","verse":11},{"label":"3 Nephi 11:11","chapterId":"3n-ch11","verse":11}],"relatedEntries":["lev","ruach_haqodesh","geulah"],"majorTheme":false},{"id":"lev","hebrew":"לֵב","hebrewRoot":"לב","transliteration":"lev","english":"Heart","category":"Humanity","definitionHeb":"הַלֵּב, מֶרְכָּז הָרְצוֹנוֹת, הַמַּחֲשָׁבוֹת, וְהָרְגָשׁוֹת. שִׁנּוּי הַלֵּב הוּא יְסוֹד הַתְּשׁוּבָה.","definitionEn":"The heart, center of will, thought, and emotion. A change of heart is the foundation of true repentance and conversion.","hebrewForms":["לֵב","לִבּוֹ","לִבָּם","לְבָבְךָ","הַלֵּב"],"verseRefs":[{"label":"1 Nephi 2:16","chapterId":"ch2","verse":16},{"label":"2 Nephi 9:39","chapterId":"2n-ch9","verse":39},{"label":"Mosiah 5:2","chapterId":"mo-ch5","verse":2},{"label":"Alma 5:7","chapterId":"al-ch5","verse":7},{"label":"Alma 32:28","chapterId":"al-ch32","verse":28}],"relatedEntries":["nefesh","teshuvah","anavah"],"majorTheme":false},{"id":"chokhmah","hebrew":"חָכְמָה","hebrewRoot":"חכם","transliteration":"chokhmah","english":"Wisdom","category":"Righteousness","definitionHeb":"חָכְמָה אֲמִתִּית הַבָּאָה מֵאֱלֹהִים. חָכְמַת הָעוֹלָם אֵינָהּ כְּחָכְמַת ה'.","definitionEn":"True wisdom that comes from God. The wisdom of the world is not as the wisdom of the Lord, which leads to eternal life.","hebrewForms":["חָכְמָה","חָכָם","חֲכָמִים","בְּחָכְמָה"],"verseRefs":[{"label":"2 Nephi 9:28","chapterId":"2n-ch9","verse":28},{"label":"2 Nephi 9:42","chapterId":"2n-ch9","verse":42},{"label":"Mosiah 2:17","chapterId":"mo-ch2","verse":17},{"label":"Alma 37:35","chapterId":"al-ch37","verse":35},{"label":"Alma 38:9","chapterId":"al-ch38","verse":9}],"relatedEntries":["davar","torah","emunah"],"majorTheme":false},{"id":"berakhah","hebrew":"בְּרָכָה","hebrewRoot":"ברך","transliteration":"berakhah","english":"Blessing","category":"Blessing","definitionHeb":"בְּרָכָה מֵאֵת ה', טוֹבָה אֱלֹהִית הַנִּתֶּנֶת לְצִיּוּת וֶאֱמוּנָה.","definitionEn":"A blessing from the Lord, divine goodness given in response to obedience and faith.","hebrewForms":["בְּרָכָה","בֵּרַךְ","בְּרָכוֹת","בָּרוּךְ","הִתְבָּרֵךְ"],"verseRefs":[{"label":"1 Nephi 17:35","chapterId":"ch17","verse":35},{"label":"2 Nephi 1:28","chapterId":"2n-ch1","verse":28},{"label":"Mosiah 2:22","chapterId":"mo-ch2","verse":22},{"label":"Mosiah 2:41","chapterId":"mo-ch2","verse":41},{"label":"Alma 45:8","chapterId":"al-ch45","verse":8}],"relatedEntries":["berit","chesed","shalom"],"majorTheme":false},{"id":"zera","hebrew":"זֶרַע","hebrewRoot":"זרע","transliteration":"zera","english":"Seed / Posterity","category":"Covenant","definitionHeb":"זֶרַע, צֶאֱצָאִים, וּפְרִי. בַּבְּרִית, זֶרַע אַבְרָהָם נוֹשֵׂא אֶת הַבְטָחוֹת הָאֱלֹהִיּוֹת.","definitionEn":"Seed, posterity, and fruit. In the covenant, the seed of Abraham carries the divine promises to all nations.","hebrewForms":["זֶרַע","זַרְעוֹ","זַרְעֲךָ","זַרְעָם"],"verseRefs":[{"label":"1 Nephi 12:10","chapterId":"ch12","verse":10},{"label":"1 Nephi 15:14","chapterId":"ch15","verse":14},{"label":"2 Nephi 3:5","chapterId":"2n-ch3","verse":5},{"label":"2 Nephi 29:2","chapterId":"2n-ch29","verse":2},{"label":"Alma 32:28","chapterId":"al-ch32","verse":28}],"relatedEntries":["berit","nachalah"],"majorTheme":false},{"id":"nachalah","hebrew":"נַחֲלָה","hebrewRoot":"נחל","transliteration":"nachalah","english":"Inheritance / Promised Land","category":"Covenant","definitionHeb":"נַחֲלָה, אֶרֶץ מוּבְטַחַת. הָאָרֶץ הַמֻּבְטַחַת הִיא סֵמֶל לְנַחֲלָה רוּחָנִית.","definitionEn":"An inheritance, a promised land. The promised land symbolizes a spiritual inheritance given to the faithful.","hebrewForms":["נַחֲלָה","נַחֲלַת","נֹחֲלִים","הַנַּחֲלָה"],"verseRefs":[{"label":"1 Nephi 2:20","chapterId":"ch2","verse":20},{"label":"2 Nephi 1:5","chapterId":"2n-ch1","verse":5},{"label":"Jacob 2:12","chapterId":"jc-ch2","verse":12},{"label":"Alma 37:45","chapterId":"al-ch37","verse":45},{"label":"3 Nephi 15:13","chapterId":"3n-ch15","verse":13}],"relatedEntries":["berit","tsiyon","zera"],"majorTheme":false},{"id":"or","hebrew":"אוֹר","hebrewRoot":"אור","transliteration":"or","english":"Light","category":"God","definitionHeb":"אוֹר אֱלֹהִי, הָאוֹר שֶׁל הַמָּשִׁיחַ הַמֵּאִיר אֶת הָעוֹלָם. הָאוֹר מְסַמֵּל אֱמֶת וְצֶדֶק.","definitionEn":"Divine light, the light of the Messiah that illuminates the world. Light symbolizes truth and righteousness.","hebrewForms":["אוֹר","אוֹרוֹ","הָאוֹר","מָאוֹר","לְאוֹר"],"verseRefs":[{"label":"1 Nephi 17:13","chapterId":"ch17","verse":13},{"label":"2 Nephi 10:14","chapterId":"2n-ch10","verse":14},{"label":"Mosiah 16:9","chapterId":"mo-ch16","verse":9},{"label":"Alma 19:6","chapterId":"al-ch19","verse":6},{"label":"Alma 38:9","chapterId":"al-ch38","verse":9},{"label":"3 Nephi 18:24","chapterId":"3n-ch18","verse":24}],"relatedEntries":["choshekh","mashiach","kavod"],"majorTheme":false},{"id":"choshekh","hebrew":"חֹשֶׁךְ","hebrewRoot":"חשך","transliteration":"choshekh","english":"Darkness","category":"Sin","definitionHeb":"חֹשֶׁךְ רוּחָנִי, הֶעְדֵּר אוֹר אֱלֹהִי. הַחֹשֶׁךְ מְסַמֵּל בּוּרוּת, חֵטְא, וְרִחוּק מֵאֱלֹהִים.","definitionEn":"Spiritual darkness, the absence of divine light. Darkness symbolizes ignorance, sin, and separation from God.","hebrewForms":["חֹשֶׁךְ","חֲשֵׁכָה","הַחֹשֶׁךְ","בַּחֹשֶׁךְ"],"verseRefs":[{"label":"1 Nephi 8:23","chapterId":"ch8","verse":23},{"label":"1 Nephi 12:17","chapterId":"ch12","verse":17},{"label":"2 Nephi 15:20","chapterId":"2n-ch15","verse":20},{"label":"Alma 19:6","chapterId":"al-ch19","verse":6},{"label":"Helaman 13:29","chapterId":"he-ch13","verse":29}],"relatedEntries":["or","chet","rishah"],"majorTheme":false},{"id":"milchamah","hebrew":"מִלְחָמָה","hebrewRoot":"לחם","transliteration":"milchamah","english":"War / Spiritual Warfare","category":"Trial","definitionHeb":"מִלְחָמָה, הֵן פִּיזִית וְהֵן רוּחָנִית. בְּסֵפֶר מוֹרְמוֹן, הַמִּלְחָמוֹת מְלַמְּדוֹת עַל אֱמוּנָה וּבִטָּחוֹן בֵּאלֹהִים.","definitionEn":"War, both physical and spiritual. In the Book of Mormon, wars teach about faith, trust in God, and the consequences of wickedness.","hebrewForms":["מִלְחָמָה","לָחַם","לֹחֵם","הַמִּלְחָמָה","מִלְחָמוֹת"],"verseRefs":[{"label":"Alma 43:47","chapterId":"al-ch43","verse":47},{"label":"Alma 46:12","chapterId":"al-ch46","verse":12},{"label":"Alma 48:14","chapterId":"al-ch48","verse":14},{"label":"Alma 56:47","chapterId":"al-ch56","verse":47},{"label":"Mormon 7:4","chapterId":"mm-ch7","verse":4}],"relatedEntries":["cherut","shalom","emunah"],"majorTheme":false},{"id":"cherut","hebrew":"חֵרוּת","hebrewRoot":"חרר","transliteration":"cherut","english":"Liberty","category":"Blessing","definitionHeb":"חֵרוּת וְחָפְשִׁי, שִׁחְרוּר מִשִּׁעְבּוּד פִּיזִי וְרוּחָנִי.","definitionEn":"Liberty and freedom, release from physical and spiritual bondage. The Book of Mormon champions liberty as a divine gift.","hebrewForms":["חֵרוּת","חָפְשִׁי","שִׁחְרוּר","בְּחֵרוּת"],"verseRefs":[{"label":"2 Nephi 1:7","chapterId":"2n-ch1","verse":7},{"label":"2 Nephi 2:27","chapterId":"2n-ch2","verse":27},{"label":"Mosiah 23:13","chapterId":"mo-ch23","verse":13},{"label":"Alma 46:12","chapterId":"al-ch46","verse":12},{"label":"Alma 46:36","chapterId":"al-ch46","verse":36},{"label":"Alma 51:6","chapterId":"al-ch51","verse":6}],"relatedEntries":["bechirah","geulah","shalom"],"majorTheme":false},{"id":"shevuah","hebrew":"שְׁבוּעָה","hebrewRoot":"שבע","transliteration":"shevuah","english":"Oath","category":"Covenant","definitionHeb":"שְׁבוּעָה, הַבְטָחָה חֲגִיגִית בְּשֵׁם ה'. הַשְּׁבוּעָה מְחַיֶּבֶת אֶת הַנִּשְׁבָּע.","definitionEn":"A solemn oath, a binding promise made in the name of God. Oaths carry sacred obligations.","hebrewForms":["שְׁבוּעָה","נִשְׁבַּע","הִשָּׁבֵעַ","שֻׁבָּע"],"verseRefs":[{"label":"1 Nephi 4:37","chapterId":"ch4","verse":37},{"label":"Alma 44:8","chapterId":"al-ch44","verse":8},{"label":"Alma 49:27","chapterId":"al-ch49","verse":27},{"label":"Alma 53:11","chapterId":"al-ch53","verse":11}],"relatedEntries":["berit","mitzvah"],"majorTheme":false},{"id":"tikvah","hebrew":"תִּקְוָה","hebrewRoot":"קוה","transliteration":"tikvah","english":"Hope","category":"Salvation","definitionHeb":"תִּקְוָה, צִפִּיָּה בְּבִטָּחוֹן לְטוֹבָה. הַתִּקְוָה בַּמָּשִׁיחַ מְעוֹדֶדֶת אֶת הַמַּאֲמִינִים.","definitionEn":"Hope, confident expectation of good. Hope in the Messiah sustains and encourages believers through trials.","hebrewForms":["תִּקְוָה","קִוָּה","מְקַוֶּה","יִקְוֶה"],"verseRefs":[{"label":"2 Nephi 31:20","chapterId":"2n-ch31","verse":20},{"label":"Jacob 2:19","chapterId":"jc-ch2","verse":19},{"label":"Alma 7:24","chapterId":"al-ch7","verse":24},{"label":"Alma 32:21","chapterId":"al-ch32","verse":21},{"label":"Ether 12:4","chapterId":"et-ch12","verse":4},{"label":"Moroni 7:42","chapterId":"mr-ch7","verse":42}],"relatedEntries":["emunah","ahavah","yeshuah"],"majorTheme":false},{"id":"zevach","hebrew":"זֶבַח","hebrewRoot":"זבח","transliteration":"zevach","english":"Sacrifice","category":"Worship","definitionHeb":"קָרְבָּן, הַקְרָבָה לֵאלֹהִים. הַזֶּבַח הָעֶלְיוֹן הוּא קָרְבַּן הַמָּשִׁיחַ.","definitionEn":"An offering, something brought near to God. The ultimate sacrifice is the Messiah's offering of Himself for all mankind.","hebrewForms":["זֶבַח","זָבַח","זְבָחִים","הַזֶּבַח","קָרְבָּן"],"verseRefs":[{"label":"1 Nephi 5:9","chapterId":"ch5","verse":9},{"label":"2 Nephi 2:7","chapterId":"2n-ch2","verse":7},{"label":"3 Nephi 9:19","chapterId":"3n-ch9","verse":19},{"label":"3 Nephi 9:20","chapterId":"3n-ch9","verse":20}],"relatedEntries":["kaparah","kehunah","berit"],"majorTheme":false},{"id":"tahor","hebrew":"טָהוֹר","hebrewRoot":"טהר","transliteration":"tahor","english":"Purity / Clean","category":"Righteousness","definitionHeb":"טָהֳרָה, נְקִיּוּת מוּסָרִית וְרוּחָנִית. הַטָּהוֹר רָאוּי לַעֲמֹד בִּפְנֵי אֱלֹהִים.","definitionEn":"Purity, moral and spiritual cleanliness. The pure are worthy to stand before God.","hebrewForms":["טָהוֹר","טְהוֹרָה","טִהֵר","הִטַּהֵר"],"verseRefs":[{"label":"2 Nephi 9:14","chapterId":"2n-ch9","verse":14},{"label":"Alma 5:24","chapterId":"al-ch5","verse":24},{"label":"Alma 7:21","chapterId":"al-ch7","verse":21},{"label":"Alma 13:12","chapterId":"al-ch13","verse":12},{"label":"3 Nephi 27:20","chapterId":"3n-ch27","verse":20}],"relatedEntries":["qodesh","tamim","tumah"],"majorTheme":false},{"id":"tumah","hebrew":"טֻמְאָה","hebrewRoot":"טמא","transliteration":"tumah","english":"Impurity / Unclean","category":"Sin","definitionHeb":"טֻמְאָה, מַצָּב שֶׁל אִי-טָהֳרָה מוּסָרִית אוֹ רוּחָנִית. הַטָּמֵא אֵינוֹ יָכוֹל לָגוּר בִּנְוֵה אֱלֹהִים.","definitionEn":"Impurity, a state of moral or spiritual uncleanness. The unclean cannot dwell in the presence of God.","hebrewForms":["טֻמְאָה","טָמֵא","טְמֵאִים","נִטְמָא"],"verseRefs":[{"label":"1 Nephi 10:21","chapterId":"ch10","verse":21},{"label":"Alma 7:21","chapterId":"al-ch7","verse":21},{"label":"Alma 32:3","chapterId":"al-ch32","verse":3},{"label":"Mormon 9:4","chapterId":"mm-ch9","verse":4}],"relatedEntries":["tahor","chet","teshuvah"],"majorTheme":false},{"id":"sefer","hebrew":"סֵפֶר","hebrewRoot":"ספר","transliteration":"sefer","english":"Book / Scripture","category":"Revelation","definitionHeb":"סֵפֶר, כְּתַב קֹדֶשׁ. הַכְּתוּבִים הַקְּדוֹשִׁים הֵם דְּבַר ה' הַכָּתוּב.","definitionEn":"A book, a sacred writing. The holy scriptures are the written word of God, preserved for future generations.","hebrewForms":["סֵפֶר","סְפָרִים","הַסֵּפֶר","כָּתוּב"],"verseRefs":[{"label":"1 Nephi 13:23","chapterId":"ch13","verse":23},{"label":"1 Nephi 19:23","chapterId":"ch19","verse":23},{"label":"2 Nephi 29:3","chapterId":"2n-ch29","verse":3},{"label":"2 Nephi 29:11","chapterId":"2n-ch29","verse":11},{"label":"Mormon 8:23","chapterId":"mm-ch8","verse":23}],"relatedEntries":["davar","nevuah","torah"],"majorTheme":false},{"id":"davar","hebrew":"דָּבָר","hebrewRoot":"דבר","transliteration":"davar","english":"Word of God","category":"Revelation","definitionHeb":"דְּבַר ה', הַמֵּסֶר הָאֱלֹהִי. דְּבַר ה' הוּא כֹּחַ לְהַנְחוֹת וּלְהוֹשִׁיעַ.","definitionEn":"The word of God, the divine message. God's word is power to guide and save all who hearken to it.","hebrewForms":["דָּבָר","דְּבַר","הַדָּבָר","דְּבָרִים","דִּבֵּר"],"verseRefs":[{"label":"1 Nephi 15:24","chapterId":"ch15","verse":24},{"label":"2 Nephi 32:3","chapterId":"2n-ch32","verse":3},{"label":"Jacob 2:8","chapterId":"jc-ch2","verse":8},{"label":"Alma 31:5","chapterId":"al-ch31","verse":5},{"label":"Alma 32:28","chapterId":"al-ch32","verse":28}],"relatedEntries":["torah","sefer","nevuah"],"majorTheme":false},{"id":"elohim","hebrew":"אֱלֹהִים","hebrewRoot":"אלה","transliteration":"elohim","english":"God / Godhead","category":"God","definitionHeb":"אֱלֹהִים, הָאֵל הָעֶלְיוֹן, בּוֹרֵא שָׁמַיִם וָאָרֶץ. אֱלֹהִים הוּא אָב לְכָל בְּנֵי הָאָדָם.","definitionEn":"God, the Most High, Creator of heaven and earth. God is the Father of all mankind and the source of all truth.","hebrewForms":["אֱלֹהִים","אֵל","הָאֱלֹהִים","אֱלֹהֵינוּ"],"verseRefs":[{"label":"1 Nephi 11:6","chapterId":"ch11","verse":6},{"label":"2 Nephi 2:14","chapterId":"2n-ch2","verse":14},{"label":"2 Nephi 11:7","chapterId":"2n-ch11","verse":7},{"label":"Mosiah 4:9","chapterId":"mo-ch4","verse":9},{"label":"Alma 30:44","chapterId":"al-ch30","verse":44},{"label":"3 Nephi 11:14","chapterId":"3n-ch11","verse":14}],"relatedEntries":["mashiach","ruach_haqodesh","kavod"],"majorTheme":false},{"id":"gilluy","hebrew":"גִּלּוּי","hebrewRoot":"גלה","transliteration":"gilluy","english":"Revelation","category":"Revelation","definitionHeb":"הִתְגַּלּוּת אֱלֹהִית, חֲשִׂיפַת הַנִּסְתָּר. אֱלֹהִים מְגַלֶּה אֶת רְצוֹנוֹ לִנְבִיאָיו.","definitionEn":"Divine revelation, the uncovering of that which is hidden. God reveals His will to His prophets and to the faithful.","hebrewForms":["גִּלּוּי","גָּלָה","נִגְלָה","הִתְגַּלּוּת"],"verseRefs":[{"label":"1 Nephi 1:8","chapterId":"ch1","verse":8},{"label":"1 Nephi 11:1","chapterId":"ch11","verse":1},{"label":"2 Nephi 32:5","chapterId":"2n-ch32","verse":5},{"label":"Alma 5:46","chapterId":"al-ch5","verse":46},{"label":"Alma 12:10","chapterId":"al-ch12","verse":10}],"relatedEntries":["nevuah","ruach_haqodesh","davar"],"majorTheme":false},{"id":"edut","hebrew":"עֵדוּת","hebrewRoot":"עוד","transliteration":"edut","english":"Testimony / Witness","category":"Revelation","definitionHeb":"עֵדוּת, הֲעָדָה עַל אֱמֶת. הָעֵד מְאַשֵּׁר אֶת דְּבַר ה' מִנִּסְיוֹנוֹ.","definitionEn":"A testimony, bearing witness to truth. The witness confirms God's word from personal experience and divine revelation.","hebrewForms":["עֵדוּת","עֵד","עֵדִים","הֵעִיד"],"verseRefs":[{"label":"2 Nephi 11:3","chapterId":"2n-ch11","verse":3},{"label":"2 Nephi 27:12","chapterId":"2n-ch27","verse":12},{"label":"Alma 4:20","chapterId":"al-ch4","verse":20},{"label":"Alma 5:46","chapterId":"al-ch5","verse":46},{"label":"Ether 5:4","chapterId":"et-ch5","verse":4}],"relatedEntries":["nevuah","emunah","sefer"],"majorTheme":false},{"id":"qibuts","hebrew":"קִבּוּץ","hebrewRoot":"קבץ","transliteration":"qibuts","english":"Gathering of Israel","category":"Covenant","definitionHeb":"קִבּוּץ גָּלֻיּוֹת, אִסּוּף עַם יִשְׂרָאֵל מִפְּזוּרָתָם. הַקִּבּוּץ הוּא קִיּוּם הַבְטָחַת הַבְּרִית.","definitionEn":"The gathering of the exiles, the assembling of Israel from their dispersal. The gathering fulfills God's covenant promise.","hebrewForms":["קִבּוּץ","קִבֵּץ","נִקְבְּצוּ","הִקָּבֵץ"],"verseRefs":[{"label":"1 Nephi 15:14","chapterId":"ch15","verse":14},{"label":"1 Nephi 22:9","chapterId":"ch22","verse":9},{"label":"2 Nephi 6:12","chapterId":"2n-ch6","verse":12},{"label":"2 Nephi 10:15","chapterId":"2n-ch10","verse":15},{"label":"3 Nephi 16:5","chapterId":"3n-ch16","verse":5},{"label":"3 Nephi 20:25","chapterId":"3n-ch20","verse":25}],"relatedEntries":["berit","tsiyon","nachalah"],"majorTheme":false},{"id":"acharit_hayamim","hebrew":"אַחֲרִית הַיָּמִים","hebrewRoot":"אחר","transliteration":"acharit hayamim","english":"Last Days","category":"Prophecy","definitionHeb":"אַחֲרִית הַיָּמִים, הַתְּקוּפָה שֶׁלִּפְנֵי בִּיאַת הַמָּשִׁיחַ. זְמַן שֶׁל גִּלּוּי, קִבּוּץ, וְהָכָנָה.","definitionEn":"The last days, the period before the Messiah's coming. A time of revelation, gathering, and preparation for God's kingdom.","hebrewForms":["אַחֲרִית הַיָּמִים","הָאַחֲרִית","בְּאַחֲרִית"],"verseRefs":[{"label":"1 Nephi 14:7","chapterId":"ch14","verse":7},{"label":"2 Nephi 3:5","chapterId":"2n-ch3","verse":5},{"label":"2 Nephi 27:1","chapterId":"2n-ch27","verse":1},{"label":"3 Nephi 21:7","chapterId":"3n-ch21","verse":7},{"label":"Mormon 8:35","chapterId":"mm-ch8","verse":35}],"relatedEntries":["qibuts","mashiach","nevuah"],"majorTheme":false},{"id":"simchah","hebrew":"שִׂמְחָה","hebrewRoot":"שמח","transliteration":"simchah","english":"Joy","category":"Blessing","definitionHeb":"שִׂמְחָה, שָׂשׂוֹן פְּנִימִי הַנּוֹבֵעַ מִקֶּשֶׁר עִם אֱלֹהִים. הַשִּׂמְחָה הִיא תַּכְלִית הַבְּרִיאָה.","definitionEn":"Joy, inner gladness flowing from a connection with God. Joy is the purpose of creation and the fruit of righteousness.","hebrewForms":["שִׂמְחָה","שָׂמֵחַ","שִׂמְחוּ","מְשַׂמֵּחַ"],"verseRefs":[{"label":"1 Nephi 8:12","chapterId":"ch8","verse":12},{"label":"2 Nephi 9:18","chapterId":"2n-ch9","verse":18},{"label":"Mosiah 4:20","chapterId":"mo-ch4","verse":20},{"label":"Alma 27:18","chapterId":"al-ch27","verse":18},{"label":"Alma 36:20","chapterId":"al-ch36","verse":20}],"relatedEntries":["shalom","berakhah","yeshuah"],"majorTheme":false},{"id":"avodah","hebrew":"עֲבוֹדָה","hebrewRoot":"עבד","transliteration":"avodah","english":"Worship / Service","category":"Worship","definitionHeb":"עֲבוֹדַת ה', שֵׁרוּת קָדוֹשׁ. עֲבוֹדַת אֱלֹהִים כּוֹלֶלֶת גַּם שֵׁרוּת הַזּוּלַת.","definitionEn":"Worship of God and sacred service. Serving God includes serving fellow man in love and humility.","hebrewForms":["עֲבוֹדָה","עָבַד","עוֹבֵד","עֲבוֹדַת"],"verseRefs":[{"label":"2 Nephi 5:10","chapterId":"2n-ch5","verse":10},{"label":"Mosiah 2:17","chapterId":"mo-ch2","verse":17},{"label":"Mosiah 18:10","chapterId":"mo-ch18","verse":10},{"label":"Alma 37:34","chapterId":"al-ch37","verse":34}],"relatedEntries":["tefilah","kehunah","qodesh"],"majorTheme":false},{"id":"pidyon","hebrew":"פִּדְיוֹן","hebrewRoot":"פדה","transliteration":"pidyon","english":"Ransom","category":"Salvation","definitionHeb":"פִּדְיוֹן, תַּשְׁלוּם מְחִיר לְשִׁחְרוּר. הַמָּשִׁיחַ שִׁלֵּם אֶת מְחִיר הַפִּדְיוֹן בְּעַד כָּל בְּנֵי הָאָדָם.","definitionEn":"Ransom, the payment of a price for release. The Messiah paid the ransom price on behalf of all mankind.","hebrewForms":["פִּדְיוֹן","פָּדָה","פְּדוּיִים","נִפְדָּה"],"verseRefs":[{"label":"Mosiah 15:9","chapterId":"mo-ch15","verse":9},{"label":"Alma 34:8","chapterId":"al-ch34","verse":8},{"label":"Alma 42:13","chapterId":"al-ch42","verse":13},{"label":"Helaman 14:17","chapterId":"he-ch14","verse":17}],"relatedEntries":["geulah","kaparah","yeshuah"],"majorTheme":false},{"id":"nefilah","hebrew":"נְפִילָה","hebrewRoot":"נפל","transliteration":"nefilah","english":"The Fall (of Man)","category":"Salvation","definitionHeb":"נְפִילַת הָאָדָם, הַמַּעֲבָר מִגַּן עֵדֶן לְעוֹלָם שֶׁל תְּמוּתָה. הַנְּפִילָה הִיא תְּנַאי לַגְּאֻלָּה.","definitionEn":"The Fall of Man, the transition from Eden to a mortal world. The Fall is a necessary condition for redemption and growth.","hebrewForms":["נְפִילָה","נָפַל","נֹפֵל","הַנְּפִילָה"],"verseRefs":[{"label":"2 Nephi 2:4","chapterId":"2n-ch2","verse":4},{"label":"2 Nephi 2:19","chapterId":"2n-ch2","verse":19},{"label":"2 Nephi 2:25","chapterId":"2n-ch2","verse":25},{"label":"2 Nephi 9:6","chapterId":"2n-ch9","verse":6},{"label":"Mosiah 3:11","chapterId":"mo-ch3","verse":11},{"label":"Alma 42:6","chapterId":"al-ch42","verse":6}],"relatedEntries":["bechirah","kaparah","geulah"],"majorTheme":false},{"id":"rishah","hebrew":"רִשְׁעָה","hebrewRoot":"רשע","transliteration":"rishah","english":"Wickedness","category":"Sin","definitionHeb":"רִשְׁעָה, הִתְנַהֲגוּת מְרוּשַׁעַת הַמְּנֻגֶּדֶת לִרְצוֹן ה'. הָרִשְׁעָה מְבִיאָה חָרְבָּן.","definitionEn":"Wickedness, evil conduct that opposes the will of God. Wickedness brings destruction and spiritual ruin.","hebrewForms":["רִשְׁעָה","רָשָׁע","רְשָׁעִים","הָרִשְׁעָה"],"verseRefs":[{"label":"1 Nephi 14:5","chapterId":"ch14","verse":5},{"label":"Mosiah 2:38","chapterId":"mo-ch2","verse":38},{"label":"Alma 41:10","chapterId":"al-ch41","verse":10},{"label":"Helaman 4:11","chapterId":"he-ch4","verse":11},{"label":"Mormon 2:15","chapterId":"mm-ch2","verse":15}],"relatedEntries":["chet","avon","gaavah"],"majorTheme":false},{"id":"bitachon","hebrew":"בִּטָּחוֹן","hebrewRoot":"בטח","transliteration":"bitachon","english":"Trust in God","category":"Salvation","definitionHeb":"בִּטָּחוֹן, הִשָּׁעֲנוּת עַל ה' בִּמְקוֹם עַל כֹּחַ הָאָדָם. הַבּוֹטֵחַ בַּה' לֹא יֵבוֹשׁ.","definitionEn":"Trust, relying on the Lord rather than on the arm of flesh. Those who trust in God shall never be confounded.","hebrewForms":["בִּטָּחוֹן","בָּטַח","בּוֹטֵחַ","הִבְטִיחַ"],"verseRefs":[{"label":"2 Nephi 4:34","chapterId":"2n-ch4","verse":34},{"label":"2 Nephi 22:2","chapterId":"2n-ch22","verse":2},{"label":"Mosiah 7:19","chapterId":"mo-ch7","verse":19},{"label":"Alma 36:3","chapterId":"al-ch36","verse":3},{"label":"Alma 57:26","chapterId":"al-ch57","verse":26}],"relatedEntries":["emunah","tikvah","tefilah"],"majorTheme":false}];